import json
from datetime import datetime

# Charger depuis un fichier
def charger_ioc(chemin):
    try:
        with open(chemin, "r", encoding="utf-8") as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError) as e:
        print(f"Erreur : {e}")
        return {}

# Sauvegarder dans un fichier
def sauvegarder_rapport(chemin, donnees):
    with open(chemin, "w", encoding="utf-8") as f:
        json.dump(donnees, f, indent=2, ensure_ascii=False, default=str)

# Exemple : générer un rapport d'alerte
rapport = {
    "generated_at": datetime.now().isoformat(),
    "analyst": "SOC Team",
    "alerts": [
        {"id": "ALT-001", "ip": "185.220.101.3", "severity": "CRITICAL"},
        {"id": "ALT-002", "ip": "10.0.0.5",     "severity": "HIGH"}
    ],
    "total": 2
}
sauvegarder_rapport("rapport.json", rapport)
print("Rapport sauvegardé")
