import json

# Réponse typique d'une API de threat intelligence
reponse_vt = {
    "data": {
        "id": "d41d8cd98f00b204e9800998ecf8427e",
        "type": "file",
        "attributes": {
            "last_analysis_stats": {
                "malicious": 32,
                "suspicious": 5,
                "undetected": 15
            },
            "names": ["malware.exe", "update.exe"],
            "tags": ["trojan", "ransomware"]
        }
    }
}

# Accès sécurisé avec .get()
attrs = reponse_vt.get("data", {}).get("attributes", {})
stats = attrs.get("last_analysis_stats", {})
malicious = stats.get("malicious", 0)
total = sum(stats.values())

print(f"Détections : {malicious}/{total}")
print(f"Tags : {', '.join(attrs.get('tags', []))}")
